export function findBestSubsubcategory(
  text,
  subcategoryId,
  subsubcategories
) {

  let best = null;
  let bestScore = 0;

  for (const subsub of subsubcategories) {

    if (Number(subsub.subcategory_id) !== Number(subcategoryId)) continue;

    const keywords =
      subsubcategoryKeywords[subsub.name.toLowerCase()];

    if (!keywords) continue;

    let score = 0;

    for (const kw of keywords) {
      if (text.includes(kw.toLowerCase())) {
        score++;
      }
    }

    if (score > bestScore) {
      bestScore = score;
      best = subsub;
    }

  }

  return best;

}